/**
 * SEO component that queries for data with
 * Gatsby's useStaticQuery React hook
 *
 * See: https://www.gatsbyjs.com/docs/use-static-query/
 */
import PropTypes from 'prop-types'
import React from 'react'
import { Helmet } from 'react-helmet'
import siteMetadata from '@/config/site/metadata'

export interface SeoProps {
  /**
   * Site description.
   */
  description?: string
  /**
   * Site language.
   */
  lang?: 'en' | string
  /**
   * HTML meta data.
   */
  meta?: Array<JSX.IntrinsicElements['meta']>
  /**
   * Site title.
   */
  title: string
}

export function Seo(props: SeoProps): React.ReactElement {
  const { description = '', lang = 'en', title } = props
  const metaDescription: string = description || siteMetadata.description
  const defaultTitle: string = siteMetadata.title

  const meta = [
    {
      name: 'author',
      content: siteMetadata.author.name,
    },
    {
      name: 'description',
      content: metaDescription,
    },
    {
      property: 'og:title',
      content: title,
    },
    {
      property: 'og:description',
      content: metaDescription,
    },
    {
      property: 'og:type',
      content: 'website',
    },
    ...(props.meta ?? []),
  ]

  return (
    <Helmet
      key="seo-title"
      htmlAttributes={{ lang }}
      title={title}
      titleTemplate={defaultTitle ? `%s | ${defaultTitle}` : undefined}
      meta={meta}
    />
  )
}

Seo.propTypes = {
  description: PropTypes.string,
  lang: PropTypes.string,
  meta: PropTypes.arrayOf(PropTypes.object),
  title: PropTypes.string.isRequired,
}

Seo.displayName = 'SEO'
export default Seo
